   107→// GetConfig supports opening and parsing flipt configuration within a target filesystem.
   108→// It initially attempts to parse the broader flipt.yml configuration file.
   109→// Failing to locate this, it falls back to parsing the .flipt.yml index file.
   110→// Server-level templates can be provided via serverTemplates; these will be used
   111→// as defaults when the repository config doesn't specify templates.
   112→func GetConfig(logger *zap.Logger, src fs.FS, serverTemplates config.TemplatesConfig) (*Config, error) {
   113→	fi, err := src.Open(configFileNameYAML)
   114→	if err != nil {
   115→		if !errors.Is(err, fs.ErrNotExist) {
   116→			return nil, err
   117→		}
   118→
   119→		fi, err = src.Open(configFileNameYML)
   120→		if err != nil {
   121→			if !errors.Is(err, fs.ErrNotExist) {
   122→				return nil, err
   123→			}
   124→
   125→			return DefaultFliptConfig(serverTemplates), nil
   126→		}
   127→	}
   128→
   129→	defer fi.Close()
   130→
   131→	return parseConfig(logger, fi, serverTemplates)
   132→}
   133→
   134→func (c *Config) List(src fs.FS) (paths []string, err error) {
   135→	err = fs.WalkDir(src, ".", func(path string, d fs.DirEntry, err error) error {
   136→		if err != nil {
   137→			return err
   138→		}
   139→
   140→		if d.IsDir() {
   141→			return nil
   142→		}
   143→
   144→		// Clean the path early to normalize and prevent path traversal issues
   145→		// This handles cases like "features.y//" -> "features.y"
   146→		cleanPath := filepath.Clean(path)
   147→
   148→		for _, matcher := range c.Matchers {
   149→			if matcher.Match(cleanPath) {
   150→				paths = append(paths, cleanPath)
   151→				break
   152→			}
   153→		}
   154→
   155→		return nil
   156→	})
   157→
   158→	// we ignore not exist errors and treat them as
   159→	// returning an empty result
   160→	if errors.Is(err, fs.ErrNotExist) {
   161→		err = nil
   162→	}
   163→
   164→	return
   165→}
