    43→// GitAuthentication returns the appropriate transport.AuthMethod for Git operations.
    44→// This method handles the complexity of converting different credential types
    45→// to the format expected by Git operations.
    46→func (c *Credential) GitAuthentication() (auth transport.AuthMethod, err error) {
    47→	switch c.config.Type {
    48→	case config.CredentialTypeBasic:
    49→		return &githttp.BasicAuth{
    50→			Username: c.config.Basic.Username,
    51→			Password: c.config.Basic.Password,
    52→		}, nil
    53→	case config.CredentialTypeSSH:
    54→		var method *gitssh.PublicKeys
    55→		if c.config.SSH.PrivateKeyBytes != "" {
    56→			method, err = gitssh.NewPublicKeys(
    57→				c.config.SSH.User,
    58→				[]byte(c.config.SSH.PrivateKeyBytes),
    59→				c.config.SSH.Password,
    60→			)
    61→		} else {
    62→			method, err = gitssh.NewPublicKeysFromFile(
    63→				c.config.SSH.User,
    64→				c.config.SSH.PrivateKeyPath,
    65→				c.config.SSH.Password,
    66→			)
    67→		}
    68→		if err != nil {
    69→			return nil, err
    70→		}
    71→
    72→		// we're protecting against this explicitly so we can disable
    73→		// the gosec linting rule
    74→		if c.config.SSH.InsecureIgnoreHostKey {
    75→			// nolint:gosec
    76→			method.HostKeyCallback = ssh.InsecureIgnoreHostKey()
    77→		}
    78→
    79→		return method, nil
    80→	case config.CredentialTypeAccessToken:
    81→		// For Git operations, access tokens need to be converted to HTTP Basic Auth
    82→		// Different providers have different conventions:
    83→		// - GitLab: username="oauth2", password=token OR user={anynonemptystring}, password=token
    84→		// - GitHub: username=token, password="" OR username={anynonemptystring}, password=token
    85→		// - BitBucket: username="x-token-auth", password=token for repo access tokens
    86→		// We'll use the BitBucket format as it requires a specific string and the others dont
    87→		return &githttp.BasicAuth{
    88→			Username: "x-token-auth",
    89→			Password: *c.config.AccessToken,
    90→		}, nil
    91→	case config.CredentialTypeGithubApp:
    92→		return NewGitHubAppCredentials(c.logger, c.config.GitHubApp)
    93→	}
    94→
    95→	return nil, fmt.Errorf("unexpected credential type: %q", c.config.Type)
    96→}
