   100→// GitHubAppCredentials holds the configuration and token source for GitHub App authentication.
   101→// This centralizes the GitHub App auth logic for both Git operations and API operations.
   102→type GitHubAppCredentials struct {
   103→	logger         *zap.Logger
   104→	clientID       string
   105→	installationID int64
   106→	apiURL         string
   107→	tokenSource    oauth2.TokenSource
