   109→
   110→// NewGitHubAppCredentials creates a GitHubAppCredentials from a GitHubAppConfig.
   111→// This function centralizes the private key reading and token source creation.
   112→func NewGitHubAppCredentials(logger *zap.Logger, c *config.GitHubAppConfig) (*GitHubAppCredentials, error) {
   113→	privateKey := []byte(c.PrivateKeyBytes)
   114→	if c.PrivateKeyPath != "" {
   115→		var err error
   116→		privateKey, err = os.ReadFile(c.PrivateKeyPath)
   117→		if err != nil {
   118→			return nil, fmt.Errorf("failed to read private key: %w", err)
   119→		}
   120→	}
   121→
   122→	appTokenSource, err := githubauth.NewApplicationTokenSource(c.ClientID, privateKey)
   123→	if err != nil {
   124→		return nil, fmt.Errorf("failed to create GitHub App application token source: %w", err)
   125→	}
   126→
   127→	ops := make([]githubauth.InstallationTokenSourceOpt, 0, 1)
   128→	if c.ApiURL != "" {
   129→		ops = append(ops, githubauth.WithEnterpriseURL(c.ApiURL))
   130→	}
   131→
   132→	installationTokenSource := githubauth.NewInstallationTokenSource(c.InstallationID, appTokenSource, ops...)
   133→
   134→	return &GitHubAppCredentials{
   135→		logger:         logger,
   136→		clientID:       c.ClientID,
   137→		installationID: c.InstallationID,
   138→		apiURL:         c.ApiURL,
   139→		tokenSource:    installationTokenSource,
   140→	}, nil
   141→}
