   148→// ClientID returns the GitHub App client ID.
   149→func (g *GitHubAppCredentials) ClientID() string {
   150→	return g.clientID
   151→}
   152→
   153→// InstallationID returns the GitHub App installation ID.
   154→func (g *GitHubAppCredentials) InstallationID() int64 {
   155→	return g.installationID
