   166→func (g *GitHubAppCredentials) SetAuth(r *http.Request) {
   167→	token, err := g.TokenSource().Token()
   168→	if err != nil {
   169→		g.logger.Error("failed to get GitHub App token", zap.Error(err))
   170→		return
   171→	}
   172→	if !token.Valid() {
   173→		g.logger.Error("GitHub App token is invalid", zap.String("token_type", token.Type()))
   174→		return
   175→	}
   176→	r.SetBasicAuth("x-token-auth", token.AccessToken)
