   214→// APIAuthentication returns authentication information for SCM API operations.
   215→// This provides a clean abstraction for different authentication methods.
   216→func (c *Credential) APIAuthentication() (*APIAuth, error) {
   217→	switch c.config.Type {
   218→	case config.CredentialTypeBasic:
   219→		return &APIAuth{
   220→			typ:      c.config.Type,
   221→			Username: c.config.Basic.Username,
   222→			Password: c.config.Basic.Password,
   223→		}, nil
   224→	case config.CredentialTypeAccessToken:
   225→		return &APIAuth{
   226→			typ:   c.config.Type,
   227→			Token: *c.config.AccessToken,
   228→		}, nil
   229→	case config.CredentialTypeSSH:
   230→		// SSH is not used for API operations, return empty auth
   231→		return &APIAuth{
   232→			typ: c.config.Type,
   233→		}, nil
   234→	case config.CredentialTypeGithubApp:
   235→		creds, err := NewGitHubAppCredentials(c.logger, c.config.GitHubApp)
   236→		if err != nil {
