	}

	installationTokenSource := githubauth.NewInstallationTokenSource(c.InstallationID, appTokenSource, ops...)

	return &GitHubAppCredentials{
		logger:         logger,
		clientID:       c.ClientID,
		installationID: c.InstallationID,
		apiURL:         c.ApiURL,
		tokenSource:    installationTokenSource,
